///|
extern "js" fn grader_install_date_now() -> Unit = "() => { globalThis.__mbt_eval_original_date_now = Date.now; Date.now = () => 731245678; }"

///|
extern "js" fn grader_restore_date_now() -> Unit = "() => { Date.now = globalThis.__mbt_eval_original_date_now; delete globalThis.__mbt_eval_original_date_now; }"

///|
test "grader now_ms dynamically delegates to Date.now" {
  grader_install_date_now()
  let actual = now_ms()
  grader_restore_date_now()
  assert_eq(actual, 731245678L)
}
